//! Chi framework recognizer (Go).
//!
//! Detects chi routers by import path and extracts direct method registrations
//! plus middleware and stdlib listen ports.

use std::collections::HashMap;

use crate::cfg::ControlFlowGraph;
use crate::framework_recognizer::{
    FrameworkRecognizer, FrameworkTopology, HttpMethod, Middleware, Route,
};

pub struct ChiRecognizer;

impl FrameworkRecognizer for ChiRecognizer {
    fn framework_id(&self) -> &str {
        "chi"
    }

    fn language(&self) -> &str {
        "go"
    }

    fn detect(
        &self,
        source: &str,
        file_path: &str,
        cfgs: &[ControlFlowGraph],
    ) -> Option<FrameworkTopology> {
        if !source.contains("\"github.com/go-chi/chi/v5\"") {
            return None;
        }

        let router_names = detect_router_names(source);
        let mut routes = Vec::new();
        let mut middleware = Vec::new();
        let mut middleware_order = 0;

        for line in source.lines() {
            let trimmed = line.trim();

            for router_name in &router_names {
                for (method_name, method) in &[
                    ("Get", HttpMethod::Get),
                    ("Post", HttpMethod::Post),
                    ("Put", HttpMethod::Put),
                    ("Delete", HttpMethod::Delete),
                    ("Patch", HttpMethod::Patch),
                    ("Method", HttpMethod::All),
                ] {
                    let pattern = format!("{}.{}(", router_name, method_name);
                    if let Some(start) = trimmed.find(&pattern) {
                        let after_paren = start + pattern.len();
                        let path = if *method_name == "Method" {
                            extract_second_string_arg(&trimmed[after_paren..])
                        } else {
                            extract_string_arg(&trimmed[after_paren..])
                        };

                        if let Some(route_path) = path {
                            let handler_name = extract_go_handler(&trimmed[after_paren..])
                                .unwrap_or_else(|| {
                                    format!(
                                        "{}_{}",
                                        method_name.to_lowercase(),
                                        sanitize_path(&route_path)
                                    )
                                });
                            let handler_cfg_index = cfgs
                                .iter()
                                .position(|cfg| cfg.function_name == handler_name);

                            routes.push(Route {
                                method: method.clone(),
                                path: route_path,
                                handler_name,
                                handler_cfg_index,
                                source_start: 0,
                                source_end: 0,
                            });
                        }
                    }
                }

                let use_pattern = format!("{}.Use(", router_name);
                if let Some(start) = trimmed.find(&use_pattern) {
                    let rest = &trimmed[start + use_pattern.len()..];
                    let name: String = rest
                        .chars()
                        .take_while(|c| c.is_alphanumeric() || *c == '_' || *c == '.')
                        .collect();
                    if !name.is_empty() {
                        middleware.push(Middleware {
                            name,
                            path_prefix: None,
                            handler_cfg_index: None,
                            order: middleware_order,
                        });
                        middleware_order += 1;
                    }
                }
            }
        }

        if routes.is_empty() {
            return None;
        }

        Some(FrameworkTopology {
            framework: "chi".to_string(),
            language: "go".to_string(),
            file_path: file_path.to_string(),
            routes,
            middleware,
            listen_port: detect_chi_port(source, &router_names),
            config: HashMap::new(),
        })
    }
}

fn detect_router_names(source: &str) -> Vec<String> {
    let mut names = Vec::new();

    for line in source.lines() {
        let trimmed = line.trim();
        if trimmed.contains("chi.NewRouter()") {
            if let Some(name) = trimmed
                .split(":=")
                .next()
                .map(|candidate| candidate.trim().to_string())
            {
                if !name.is_empty() {
                    names.push(name);
                }
            }
        }
    }

    if names.is_empty() {
        names.push("r".to_string());
        names.push("router".to_string());
    }

    names
}

fn extract_go_handler(s: &str) -> Option<String> {
    let after_path = s.rfind(',')? + 1;
    let rest = s[after_path..].trim();
    if rest.starts_with("func(") || rest.starts_with("func (") {
        return None;
    }

    let name: String = rest
        .chars()
        .take_while(|c| c.is_alphanumeric() || *c == '_' || *c == '.')
        .collect();

    if name.is_empty() {
        None
    } else {
        Some(name)
    }
}

fn extract_string_arg(s: &str) -> Option<String> {
    let s = s.trim();
    let quote = s.chars().next()?;
    if quote != '"' {
        return None;
    }
    let rest = &s[1..];
    let end = rest.find('"')?;
    Some(rest[..end].to_string())
}

fn extract_second_string_arg(s: &str) -> Option<String> {
    let first = s.find('"')?;
    let second = s[first + 1..].find('"')? + first + 1;
    let rest = &s[second + 1..];
    extract_string_arg(rest.trim_start_matches(',').trim())
}

fn detect_chi_port(source: &str, router_names: &[String]) -> Option<u16> {
    for line in source.lines() {
        let trimmed = line.trim();
        if !trimmed.contains("http.ListenAndServe(") {
            continue;
        }

        for router_name in router_names {
            if !trimmed.contains(router_name) {
                continue;
            }

            if let Some(addr) = extract_string_arg(
                trimmed
                    .split("http.ListenAndServe(")
                    .nth(1)
                    .unwrap_or_default(),
            ) {
                if let Some(port) = parse_addr_port(&addr) {
                    return Some(port);
                }
            }
        }
    }
    None
}

fn parse_addr_port(addr: &str) -> Option<u16> {
    if let Some(port) = addr.rsplit(':').next() {
        return port.parse::<u16>().ok();
    }
    None
}

fn sanitize_path(path: &str) -> String {
    path.chars()
        .map(|c| if c.is_alphanumeric() { c } else { '_' })
        .collect::<String>()
        .trim_matches('_')
        .to_string()
}
